text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과할 경우 공개 릴리스 목표는 금요일 15:00 KST이다.",
        "condition": "스모크 테스트 통과 시"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐 확정 일정은 아님"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나, 확정 소유자는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음"
      },
      {
        "risk": "README 설치 절차가 오래된 상태이면 릴리스 노트가 사용자를 오도할 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유",
      "due": "금요일 10:00 KST",
      "status": "미완료",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "미완료",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차 검토",
      "due": "목요일 가능 시",
      "status": "소유자 미지정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 통과 여부 확인",
      "Doyun의 실패 트리아지 노트 작성 완료 여부 확인",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과 확인",
      "README 설치 절차 검토 담당자 지정 필요 여부 확인",
      "최종 릴리스 승인 권한자 식별 필요",
      "릴리스 노트에 내부 수요일 스트레치 목표를 기재할지 결정 필요"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고 여부",
      "프로덕션 장애 여부",
      "법무 승인 요구사항",
      "지정되지 않은 소유자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 회의 기록에 없는 사실은 추가하지 않는다.",
    "확정 결정과 제안, 리스크, 미결 사항을 혼합하지 않는다.",
    "고객, 예산, 보안, 장애, 법무 관련 사실은 명시된 범위를 넘어서 서술하지 않는다.",
    "소유자와 마감일은 기록에 명시된 경우에만 채운다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다."
  ]
}
